void ScreenHostViewBase::transitionBegins()
{
    //InteractionHostToDeviceAnimation
    //When screen transition begins execute C++ code
    //Execute C++ code
    //When changing screen, set the power images visible or invisible based on power state
    int temp = presenter->getPowerState();
    imageSource.setVisible(SOURCESTATE == temp);
    imageSink.setVisible(SINKSTATE == temp);
    animatedImageOutput.setVisible(false);
    animatedImageInput.setVisible(false);
    imageCharging.setVisible(SINKSTATE == temp);
    imageSource.invalidate();
    imageSink.invalidate();
    animatedImageOutput.invalidate();
    animatedImageInput.invalidate();
    imageCharging.invalidate();
    
    if(presenter->getCurrentScreen() == WAITINGSCREEN)   //prev screen was waiting
    {
    imageHost.setVisible(true);
    imageHost.invalidate();
    animatedImageDeviceToHost.setVisible(false);
    animatedImageDeviceToHost.invalidate();
    }
    
    if(presenter->getCurrentScreen() == DEVICESCREEN)	//prev screen was device
    {
    imageHost.setVisible(false);
    imageHost.invalidate();
    animatedImageDeviceToHost.setVisible(true);
    animatedImageDeviceToHost.startAnimation(false, true, false);
    animatedImageDeviceToHost.invalidate();
    }
    
    if(presenter->getPowerState() != SOURCESTATE)
    {
    flexButtonSwapToSink.setTouchable(false);
    flexButtonSwapToSource.setTouchable(true);
    }
    
    if(presenter->getPowerState() != SINKSTATE)
    {
    flexButtonSwapToSink.setTouchable(true);
    flexButtonSwapToSource.setTouchable(false);
    }
    
    //Update screen
    presenter->setCurrentScreen(HOSTSCREEN);
}

